const prev = $('Store 7').first().json;
const question = prev._question;
const devTrafficRaw = prev._devTraffic;
const piholeRaw = $json;

const srvObj = Array.isArray(prev._servers) ? prev._servers[0] : prev._servers;
const servers = srvObj?.servers || [];
const wazObj = Array.isArray(prev._wazuh) ? prev._wazuh[0] : prev._wazuh;
const insObj = Array.isArray(prev._insights) ? prev._insights[0] : prev._insights;
const alertObj = Array.isArray(prev._alerts) ? prev._alerts[0] : prev._alerts;
const networkRaw = prev._network;
const netObj = Array.isArray(networkRaw) ? networkRaw[0] : networkRaw;
const devObj = Array.isArray(devTrafficRaw) ? devTrafficRaw[0] : devTrafficRaw;
const phObj = Array.isArray(piholeRaw) ? piholeRaw[0] : piholeRaw;

let context = '## Current Dashboard State\n\n';

// Alerts
const alerts = alertObj?.alerts || [];
if (alerts.length > 0) {
  context += `### Active Alerts (${alerts.length})\n`;
  for (const a of alerts) context += `- [${a.severity.toUpperCase()}] ${a.title}: ${a.body}\n`;
  context += '\n';
} else {
  context += '### Active Alerts: None\n\n';
}

// Network
if (netObj) {
  context += `### Network: ${netObj.total || 0} hosts, ${netObj.available || 0} online, ${netObj.unavailable || 0} offline\n\n`;
}

// Device Traffic
const devices = devObj?.devices || [];
if (devices.length > 0) {
  context += '### Device Network Traffic (current)\n';
  context += '| Device | In | Out | Total |\n|---|---|---|---|\n';
  for (const d of devices) {
    const inK = Math.round(d.in_bps / 1000);
    const outK = Math.round(d.out_bps / 1000);
    context += `| ${d.name} (${d.ip}) | ${inK} Kbps | ${outK} Kbps | ${inK + outK} Kbps |\n`;
  }
  context += '\n';
}

// Pi-hole DNS
if (phObj?.combined) {
  const c = phObj.combined;
  context += `### Pi-hole DNS (combined from 2 servers)\n`;
  context += `- Total queries: ${c.total_queries?.toLocaleString()}\n`;
  context += `- Blocked: ${c.blocked?.toLocaleString()} (${c.percent_blocked?.toFixed(1)}%)\n`;
  context += `- Cached: ${c.cached?.toLocaleString()}\n\n`;

  if (phObj.servers?.length > 0) {
    context += '**Per-server:**\n';
    for (const s of phObj.servers) {
      context += `- ${s.name} (${s.ip}): ${s.total} queries, ${s.blocked} blocked (${s.percent_blocked?.toFixed(1)}%)\n`;
    }
    context += '\n';
  }

  if (phObj.top_clients?.length > 0) {
    context += '**Top DNS clients:**\n';
    for (const cl of phObj.top_clients.slice(0, 5)) {
      context += `- ${cl.name || cl.ip}: ${cl.count?.toLocaleString()} queries\n`;
    }
    context += '\n';
  }

  if (phObj.top_blocked?.length > 0) {
    context += '**Top blocked domains:**\n';
    for (const b of phObj.top_blocked.slice(0, 5)) {
      context += `- ${b.domain}: ${b.count?.toLocaleString()} blocked\n`;
    }
    context += '\n';
  }
}


// Dashboard Auth Events (basic auth 401/403 against the home dashboard).
// The summary endpoint classifies each 401 into real_attempts (bad password),
// asset_probes (browsers fetching favicons/manifests without creds — normal),
// monitor_probes (Zabbix/Ansible health checks), and endpoint_probes (everything else).
// The "concerning" bucket is external IPs with real_attempts or endpoint_probes —
// the only number a human or assistant should headline.
const authRaw = prev._auth;
const authObj = Array.isArray(authRaw) ? authRaw[0] : authRaw;
if (authObj) {
  const cls = authObj.classification || {};
  const concerning = authObj.concerning || { total: 0, by_ip: [] };
  const ext = authObj.external || {};
  const windowDays = authObj.window_days || 7;

  context += `### Dashboard Auth Events (last ${windowDays}d)\n`;

  if ((concerning.total || 0) === 0) {
    context += `- No suspicious authentication activity. `;
    context += `The dashboard received ${authObj.total || 0} credential-less 401s: `;
    context += `${cls.monitor_probes || 0} from internal monitoring (Zabbix, Ansible health-checks), `;
    context += `${cls.asset_probes || 0} from browsers fetching favicons/manifests/static assets without Basic Auth creds (this is normal browser behavior, not an attack), `;
    context += `and ${cls.endpoint_probes || 0} other probes. Zero bad-password attempts.\n\n`;
  } else {
    context += `- ${concerning.total} concerning event(s) from external IPs: `;
    context += `${ext.real_attempts || 0} bad-password, ${ext.endpoint_probes || 0} endpoint probe(s).\n`;
    if (concerning.by_ip && concerning.by_ip.length > 0) {
      context += '**Concerning source IPs:**\n';
      for (const ip of concerning.by_ip.slice(0, 10)) {
        const kind = ip.real_attempts > 0 ? 'bad-password' : 'endpoint-probe';
        context += `- ${ip.ip}: ${ip.count} (${kind}), last ${ip.last_seen}\n`;
      }
    }
    context += `- Context (not attacks): ${cls.monitor_probes || 0} internal monitoring probes + ${cls.asset_probes || 0} browser asset fetches also produced 401s in the same window.\n\n`;
  }

  // Only surface bad-password attempts if any actually exist.
  const realAttempts = (authObj.recent || []).filter(r => r.had_auth).slice(0, 5);
  if (realAttempts.length > 0) {
    context += '**Recent bad-password attempts:**\n';
    for (const r of realAttempts) {
      context += `- ${r.occurred_at} ${r.src_ip} ${r.method} ${r.path} (UA: ${(r.user_agent||'').slice(0,60)})\n`;
    }
    context += '\n';
  }
}

// Servers
if (servers.length > 0) {
  context += '### Servers\n';
  context += '| Name | CPU | Memory | Disk | Status |\n|---|---|---|---|---|\n';
  for (const s of servers) {
    const status = s.available === false ? 'OFFLINE' : 'Online';
    context += `| ${s.name} | ${s.cpu ?? 'n/a'}% | ${s.memory ?? 'n/a'}% | ${s.disk_pused ?? 'n/a'}% | ${status} |\n`;
  }
  context += '\n';
}

// Wazuh
if (wazObj) {
  context += `### Security (Wazuh)\n`;
  context += `- Total alerts (24h): ${wazObj.total_alerts ?? 'unknown'}\n`;
  context += `- Critical: ${wazObj.critical_alerts ?? 0}, High: ${wazObj.high_alerts ?? 0}, Medium: ${wazObj.medium_alerts ?? 0}\n`;
  context += `- Active agents: ${wazObj.agents_active ?? 'unknown'} / ${wazObj.agents_total ?? 'unknown'}\n\n`;
}

// Insights
if (insObj) {
  if (insObj.failed_auth?.total > 0) {
    context += `### Failed Authentication: ${insObj.failed_auth.total} attempts\n`;
    for (const u of (insObj.failed_auth.by_user || [])) {
      context += `- User "${u.user}" on ${u.agents?.join(', ')}: ${u.count} failures\n`;
    }
    context += '\n';
  }
  if (insObj.high_alerts?.length > 0) {
    context += `### High Severity Alerts\n`;
    for (const a of insObj.high_alerts.slice(0, 5)) {
      context += `- ${a.description} (x${a.count}) on ${a.agents?.map(ag => ag.name).join(', ')}\n`;
    }
    context += '\n';
  }
}

const systemPrompt = `You are a helpful voice assistant for a homelab dashboard. Answer questions about the current state of the infrastructure concisely and conversationally — your answers will be spoken aloud, so keep them natural and brief (2-4 sentences max unless the user asks for detail).

When asked about authentication attempts, hacking attempts, or whether the server is under attack: headline the "concerning" count from the Dashboard Auth Events section, not the raw total. Credential-less 401s from internal monitoring (Zabbix, Ansible) and browser asset fetches (favicons, manifests) are NOT attacks — do not describe them as "failed authentication attempts" or "hacking attempts." If the concerning count is zero, say so plainly.

You have access to real-time data from Zabbix (servers, network traffic), Wazuh (security), Pi-hole (DNS filtering), and the alert system.

${context}

Answer based on this data. Be specific with numbers and server names.`;

const requestBody = JSON.stringify({
  model: 'gpt-4o-mini',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: question }
  ],
  temperature: 0.5,
  max_tokens: 300
});

return [{ json: { requestBody } }];
